INSERT INTO search_anchors (slug, city, radius_miles, status, last_batch_at, next_batch_after, notes, ring, position) VALUES ('tacoma-wa-25mi', 'Tacoma, WA', 25, 'in_progress', '2026-05-08', '2026-05-22', 'Batch 5 (2026-05-08 PM): 21 rows pulled across 5 sources — 4 i9 Sports leagues (Federal Way Todd Beamer + Lakewood Lakes HS Spring 2026 soccer/baseball), 4 US Sports Camps Nike Soccer (Hilltop Heritage MS, Tacoma Soccer Center, SERA Sports Complex), 3 Challenger Sports Foundational Skills Soccer (DuPont Powder Works Wks 1-2, NorPoint at Meeker MS Tacoma), 5 Annie Wright Schools Summer@AW (Sawyer schedules now live — week 1 sports + arts), 5 Charles Wright Academy sports clinics (Volleyball/Tennis/Soccer/Basketball/Flag Football). New no_camps domains: sumnerwa.gov, pierce.ctc.edu, tacomacc.edu. New stale_listings: bonneylake.gov (PDFs + Tyler portal), tacoma.uw.edu (Pre-Collegiate Programs no 2026 dates). New blocked: townofsteilacoom.org (URL paths broken). New partial: soundviewlittleleague.teamsnapsites.com + gigharborlittleleague.org (Spring 2026 registration open but season schedules not posted). aw.org promoted stale_listings → partial (Sawyer now populated, 15+ more sessions remain). charleswright.org partial (105+ Homeroom sessions, only sports clinics pulled). Schema gap surfaced this batch: 8 leagues use program_type=''league'' but the submit endpoint + import script were not forwarding program_type/registration_deadline/schedule_text. Both patched this run. Carry-over still open: parkstacoma.gov (~200), penmetparks.org (188 gated), auburnwa.gov (~120), Puyallup specialty camps, school district summer programs, Skyhawks via partner portals, Lakewood club leagues, kentwa.gov entry-point. Batch 4 (2026-05-08 AM): 34 rows — Mountaineers Tacoma Branch (10), Sound Life Day Camp Tacoma (7), Wolf Camp Puyallup (5), i9 Sports Office 426/489/Kent (7), Breakthrough Basketball (5). After current carry-over, Ring 1 Anchor 2 (Seattle, WA 25mi) becomes priority.', 1, 0) ON CONFLICT(slug) DO UPDATE SET city=excluded.city, radius_miles=excluded.radius_miles, status=excluded.status, last_batch_at=excluded.last_batch_at, next_batch_after=excluded.next_batch_after, notes=excluded.notes, ring=excluded.ring, position=excluded.position, updated_at=datetime('now');
