INSERT INTO search_domains (domain, organization, area_covered, last_checked, result, camps_pulled, next_recheck_after, notes, permanent_skip) VALUES ('kentwa.gov', 'City of Kent', 'tacoma-25mi', '2026-05-06', 'blocked', 0, '2026-06-05', 'Site URL structure breaks Chrome extension access on JS reads ("Cannot access chrome-extension URL"). Multiple recreation/youth-teen URL guesses all 404. Need a working entry-point URL. Recheck via finding their ActiveNet/CommunityPass/rec1 portal URL through a different referrer.', 0) ON CONFLICT(domain) DO UPDATE SET organization=excluded.organization, area_covered=excluded.area_covered, last_checked=excluded.last_checked, result=excluded.result, camps_pulled=excluded.camps_pulled, next_recheck_after=excluded.next_recheck_after, notes=excluded.notes, permanent_skip=excluded.permanent_skip, updated_at=datetime('now');
INSERT INTO search_domains (domain, organization, area_covered, last_checked, result, camps_pulled, next_recheck_after, notes, permanent_skip) VALUES ('mountaineers.org', 'The Mountaineers Tacoma Branch', 'tacoma-25mi', '2026-05-08', 'camps_extracted', 10, '2026-06-07', 'Batch 4 follow-up run visited all 12 individual 2026 session pages. 10 rows extracted: 5 day camps for grades 1-7 ages 6-13, 2 teen overnight adventures ages 13-17 (Rock Climbing + Backpacking), plus 3 alternate-week duplicates. Skipped both Teanaway Overnight sessions (Jul 20-24, Aug 3-7) because session pages do not state ages. Spring Break Apr 6-10 already past. Almost all sessions FULL with waitlists 10-35 deep; only Teen Adventures Backpacking shows 1 spot open. Day camps at Tacoma Program Center 2302 N 30th St 98403, Friday at Point Defiance Park, climbing field trips at Exit 38 near North Bend. Pricing tiers: standard day $385/$410, water-themed day $410/$435, teen overnight $475-$520, Teanaway overnight $500-$575. Contact sarahh@mountaineers.org.', 0) ON CONFLICT(domain) DO UPDATE SET organization=excluded.organization, area_covered=excluded.area_covered, last_checked=excluded.last_checked, result=excluded.result, camps_pulled=excluded.camps_pulled, next_recheck_after=excluded.next_recheck_after, notes=excluded.notes, permanent_skip=excluded.permanent_skip, updated_at=datetime('now');
