INSERT INTO search_domains (domain, organization, area_covered, last_checked, result, camps_pulled, next_recheck_after, notes, permanent_skip) VALUES ('wolfcamp.org', 'Wolf Camp & School of Natural Science', 'tacoma-25mi', '2026-05-08', 'camps_extracted', 5, '2026-06-07', 'Puyallup-Tacoma day camps at Clark''s Creek Park 1710 12th Ave SW Puyallup 98371. Wilderness/nature themes ages 7-15 $495 sliding scale. Sessions Jul 13-Aug 28. Page has typo "August 10-14, 2025" for what should be 2026 — skipped that session.', 0) ON CONFLICT(domain) DO UPDATE SET organization=excluded.organization, area_covered=excluded.area_covered, last_checked=excluded.last_checked, result=excluded.result, camps_pulled=excluded.camps_pulled, next_recheck_after=excluded.next_recheck_after, notes=excluded.notes, permanent_skip=excluded.permanent_skip, updated_at=datetime('now');
INSERT INTO search_domains (domain, organization, area_covered, last_checked, result, camps_pulled, next_recheck_after, notes, permanent_skip) VALUES ('i9sports.com', 'i9 Sports (Office 426 Puyallup, Office 489 Federal Way/Lakewood, Kent/Covington)', 'tacoma-25mi', '2026-05-08', 'camps_extracted', 11, '2026-06-07', 'Cumulative 11 leagues across batches 4 + 5. Batch 5 added 4 Spring 2026 leagues at Lakes HS Lakewood (10320 Farwest Dr SW 98498) and Todd Beamer HS Federal Way (35999 16th Ave S 98003), all soccer + baseball. Office 426 covers Puyallup Heritage Rec Center + Rogers-Ram Field. Kent Flag Football at Kentwood HS Covington. Clean schema.org JSON-LD on franchise + venue pages. Spring Federal Way leagues mid-season (4/25-6/6); summer Puyallup leagues start 7/12.', 0) ON CONFLICT(domain) DO UPDATE SET organization=excluded.organization, area_covered=excluded.area_covered, last_checked=excluded.last_checked, result=excluded.result, camps_pulled=excluded.camps_pulled, next_recheck_after=excluded.next_recheck_after, notes=excluded.notes, permanent_skip=excluded.permanent_skip, updated_at=datetime('now');
